from openpyxl import load_workbook
from openpyxl.styles import Font
from openpyxl.formula.translate import Translator
from openpyxl.utils import get_column_letter
import csv, json, math, os
from urllib.request import Request, urlopen

path='/root/test-supply.xlsx'
# Load sources
# PWT 10.0
pwt_path='/root/data/pwt100.xlsx'
pwt_wb=load_workbook(pwt_path, read_only=True, data_only=True)
pwt_ws=pwt_wb['Data']
headers=[c for c in next(pwt_ws.iter_rows(min_row=1,max_row=1,values_only=True))]
idx={h:i for i,h in enumerate(headers)}
pwt_rnna={}
pwt_rgdpna={}
pwt_delta={}
for row in pwt_ws.iter_rows(min_row=2, values_only=True):
    if row[idx['countrycode']]=='GEO':
        y=row[idx['year']]
        if row[idx['rnna']] is not None: pwt_rnna[y]=float(row[idx['rnna']])
        if row[idx['rgdpna']] is not None: pwt_rgdpna[y]=float(row[idx['rgdpna']])
        if row[idx['delta']] is not None: pwt_delta[y]=float(row[idx['delta']])

# WEO DB.NOMICS 2024-10 (IMF source); if unavailable use stored files
weo={}
for code,fn in [('NGDP_R','/root/data/weo_obs_0.json'),('NGDP_RPCH','/root/data/weo_obs_1.json')]:
    data=json.load(open(fn))
    doc=data['series']['docs'][0]
    vals={}
    if 'values' in doc and 'period' in doc:
        for p,v in zip(doc['period'],doc['values']):
            if v is not None:
                vals[int(p)]=float(v)
    elif 'observations' in doc:
        for p,obs in doc['observations'].items():
            v=obs[0] if isinstance(obs,(list,tuple)) else obs
            if v is not None:
                vals[int(p)]=float(v)
    else:
        # DB.NOMICS sometimes stores in dimensions_values_labels + values
        raise RuntimeError('unknown WEO json structure')
    weo[code]=vals
print('WEO NGDP_R range', min(weo['NGDP_R']), max(weo['NGDP_R']), list(weo['NGDP_R'].items())[-5:])
print('WEO growth range', min(weo['NGDP_RPCH']), max(weo['NGDP_RPCH']), list(weo['NGDP_RPCH'].items())[-5:])

# ECB CFC values: national currency units. Convert to millions of Lari to align with PWT real capital stock in million 2017 Lari-ish.
cfc={}
with open('/root/data/cfc.csv', newline='', encoding='utf-8-sig') as f:
    r=csv.DictReader(f)
    for row in r:
        if row.get('OBS_VALUE'):
            cfc[int(row['TIME_PERIOD'])]=float(row['OBS_VALUE'])/1_000_000.0

# Extend PWT rnna 2020-2023 if PWT release only goes to 2019. Use PIM-style growth from real GDP and average depreciation from latest PWT years as a neutral extension.
rnna=dict(pwt_rnna)
avg_delta=sum(pwt_delta[y] for y in sorted(pwt_delta)[-8:])/8
# Estimate gross real investment share from capital accumulation in last PWT years: I_t = K_t-(1-d)K_{t-1}
inv_share=[]
for y in range(2011,2020):
    if y in rnna and y-1 in rnna and y in pwt_rgdpna:
        inv=rnna[y]-(1-avg_delta)*rnna[y-1]
        inv_share.append(inv/pwt_rgdpna[y])
avg_inv_share=sum(inv_share[-9:])/len(inv_share[-9:])
for y in range(2020,2024):
    if y not in rnna:
        # Use WEO/World real GDP level if available, otherwise grow PWT rgdpna by WEO pct
        if y in weo['NGDP_R']:
            # scale WEO level to PWT real GDP units using 2019 overlap
            scale=pwt_rgdpna[2019]/weo['NGDP_R'][2019]
            y_level=weo['NGDP_R'][y]*scale
        else:
            y_level=pwt_rgdpna[y-1]*(1+weo['NGDP_RPCH'].get(y,0)/100)
        rnna[y]=(1-avg_delta)*rnna[y-1]+avg_inv_share*y_level

# HP filter for LnZ, lambda 100. Min sum(y-t)^2 + lambda sum(second diff)^2
# Solve via simple dense linear algebra (n=22) using Gaussian elimination
alpha=0.35
years_hp=list(range(2002,2024))
# Need K and Y aligned in millions of Lari; use WEO NGDP_R billions -> millions, PWT rnna already millions
lnz=[]
for y in years_hp:
    K=rnna[y]
    Y=weo['NGDP_R'][y]*1000.0
    lnz.append(math.log(Y)-alpha*math.log(K))
n=len(lnz); lam=100.0
A=[[0.0]*n for _ in range(n)]
b=lnz[:]
for i in range(n): A[i][i]=1.0
for i in range(n-2):
    coeff=[1,-2,1]
    for a,ca in enumerate(coeff):
        for bb,cb in enumerate(coeff):
            A[i+a][i+bb]+=lam*ca*cb
# gaussian solve
M=[row[:] + [b[i]] for i,row in enumerate(A)]
for col in range(n):
    piv=max(range(col,n), key=lambda r: abs(M[r][col]))
    M[col],M[piv]=M[piv],M[col]
    pv=M[col][col]
    for j in range(col,n+1): M[col][j]/=pv
    for r in range(n):
        if r==col: continue
        fac=M[r][col]
        if fac:
            for j in range(col,n+1): M[r][j]-=fac*M[col][j]
trend=[M[i][n] for i in range(n)]

wb=load_workbook(path)
# workbook calc settings
try:
    wb.calculation.fullCalcOnLoad = True
    wb.calculation.forceFullCalc = True
    wb.calculation.calcMode = 'auto'
except Exception: pass

# PWT sheet
ws=wb['PWT']
ws['C1']='rnna_extended'
for r in range(2,36):
    y=int(ws.cell(r,1).value)
    ws.cell(r,2).value=rnna.get(y)
    if y>2019:
        ws.cell(r,3).value=rnna.get(y)
    else:
        ws.cell(r,3).value=None

# WEO_Data rows 8:51, columns C-D
ws=wb['WEO_Data']
for r in range(8,52):
    y=int(ws.cell(r,2).value)
    if y<=2027:
        ws.cell(r,3).value=weo['NGDP_R'].get(y)
        ws.cell(r,4).value=weo['NGDP_RPCH'].get(y)
    else:
        ws.cell(r,4).value='=$D$35'
        ws.cell(r,3).value=f'=C{r-1}*(1+D{r}/100)'

# CFC data
ws=wb['CFC data']
for r in range(2,30):
    y=int(ws.cell(r,2).value)
    ws.cell(r,3).value=cfc.get(y)
    ws.cell(r,4).value=f'=IFERROR(VLOOKUP(B{r},PWT!$A:$B,2,FALSE),"")'
    ws.cell(r,5).value=f'=IFERROR(C{r}/D{r},"")'

# Production
ws=wb['Production']
ws['B2']=alpha
ws['B3']='=AVERAGE(\'CFC data\'!E22:E29)'
# HP input section
for r,y in zip(range(6,28), years_hp):
    ws.cell(r,4).value=f'=VLOOKUP(C{r},PWT!$A:$B,2,FALSE)'
    ws.cell(r,5).value=f'=VLOOKUP(C{r},WEO_Data!$B:$C,2,FALSE)*1000'
    ws.cell(r,6).value=f'=LN(D{r})'
    ws.cell(r,7).value=f'=LN(E{r})'
    ws.cell(r,11).value=f'=G{r}-$B$2*F{r}'
    ws.cell(r,12).value=trend[r-6]  # Solver output cells
    if 7 <= r <= 26:
        ws.cell(r,13).value=f'=L{r-1}-2*L{r}+L{r+1}'
    else:
        ws.cell(r,13).value=0
    ws.cell(r,14).value=f'=K{r}-L{r}'
ws['P5']='=SUMXMY2(K6:K27,L6:L27)+100*SUMSQ(M7:M26)'
# Main production table
for r in range(36,76):
    y=int(ws.cell(r,3).value)
    # K/Y actual for 2002-2023 only
    if y<=2023:
        ws.cell(r,4).value=f'=E{r}/F{r}'
        ws.cell(r,5).value=f'=VLOOKUP(C{r},PWT!$A:$B,2,FALSE)'
    else:
        ws.cell(r,4).value=''
        ws.cell(r,5).value=f'=F{r}*AVERAGE($D$49:$D$57)'
    ws.cell(r,6).value=f'=VLOOKUP(C{r},WEO_Data!$B:$C,2,FALSE)*1000'
    if y<=2023:
        ws.cell(r,7).value=f'=L{r-30}'  # row 36->L6
    else:
        # extend trend to 2041 with Excel TREND based on 2002-2023 history
        ws.cell(r,7).value=f'=TREND($G$36:$G$57,$C$36:$C$57,C{r})'
    # Ystar in millions GEL: exp(lnZtrend)*K^alpha. For baseline use derived capital K.
    ws.cell(r,8).value=f'=EXP(G{r})*E{r}^$B$2'
    if 2026 <= y <= 2033:
        ws.cell(r,9).value=f'=VLOOKUP(C{r},Investment!$B:$C,2,FALSE)'
    else:
        ws.cell(r,9).value=0
    if r==36:
        ws.cell(r,10).value='=I36'
        ws.cell(r,11).value='=E36+J36'
    else:
        ws.cell(r,10).value=f'=I{r}+(1-$B$3)*J{r-1}'
        ws.cell(r,11).value=f'=E{r}+J{r}'
    ws.cell(r,12).value=f'=EXP(G{r})*K{r}^$B$2'
    ws.cell(r,13).value=f'=L{r}-H{r}'
    ws.cell(r,14).value=f'=F{r}+M{r}'
    if r==36:
        ws.cell(r,15).value=''
        ws.cell(r,16).value=''
    else:
        ws.cell(r,15).value=f'=N{r}/N{r-1}-1'
        ws.cell(r,16).value=f'=F{r}/F{r-1}-1'

# basic number formats
for wsname in ['PWT','WEO_Data','CFC data','Production']:
    ws=wb[wsname]
    for row in ws.iter_rows():
        for c in row:
            if isinstance(c.value,(int,float)):
                c.number_format='0.000'
# percent formats
for c in wb['Production']['O'][35:75]+wb['Production']['P'][35:75]:
    c.number_format='0.00%'
wb['Production']['B3'].number_format='0.00%'
for c in wb['CFC data']['E'][1:]: c.number_format='0.00%'

wb.save(path)
print('saved', path)
print('rnna 2019-2023', {y:rnna[y] for y in range(2019,2024)})
print('avg_delta pwt extension', avg_delta, 'avg inv share', avg_inv_share)
